import re

def checkAdminPassword(password):
    common_passwords = {'password', '123456', 'admin', '123456789', 'qwerty', 'password123', 'abc123', 'letmein', 'dragon', '1234567890'}
    if password in common_passwords:
        return False
    if len(password) < 12:
        return False
    if not re.search(r'[a-z]', password):
        return False
    if not re.search(r'[A-Z]', password):
        return False
    if not re.search(r'\d', password):
        return False
    if not re.search(r'[!@#$%^&*()-_=+[]{}|;:,.<>/?]', password):
        return False
    if any(char.isspace() for char in password):
        return False
    return True

